import React, {useRef, useState} from "react";
import { useParams } from "react-router-dom";
import { useProductDetailScreenModel } from "./ProductDetailsScreenModel";
import styles from "./ProductDetailScreen.module.css";
import Header from "../../../presentation/components/header/Header";
import TopNavBar from "../../../presentation/components/topNavBar/TopNavBar";

const ProductDetailsScreen: React.FC = () => {
    const { productName } = useParams();
    const { product, loading, error } = useProductDetailScreenModel(productName);
    const thumbnailRef = useRef<HTMLDivElement>(null);

    const scrollThumbnails = (direction: "left" | "right") => {
        if (thumbnailRef.current) {
            thumbnailRef.current.scrollBy({
                left: direction === "left" ? -100 : 100,
                behavior: "smooth",
            });
        }
    };
    if (loading) return <p>Loading...</p>;
    if (error) return <p style={{ color: "red" }}>{error}</p>;
    if (!product) return <p>No product found</p>;

    return (
        <div className={styles.productDetailPageRoot}>
            <TopNavBar />
            <Header />
            <div className={styles.productDetailPage}>
                <div className={styles.topPartProductDetails}>
                    <div className={styles.productDetailsImageContainer}>
                        <img src={mainImage} alt={product.name} className={styles.mainImage}/>

                        <div className={styles.thumbnailWrapper}>
                            <button className={styles.scrollButton} onClick={() => scrollThumbnails("left")}>‹</button>

                            <div className={styles.thumbnailContainer} ref={thumbnailRef}>
                                {product.images_additional.length > 0 ? (
                                    product.images_additional.map((image, index) => (
                                        <img
                                            key={index}
                                            src={image}
                                            alt={`Thumbnail ${index}`}
                                            className={styles.thumbnail}
                                            onClick={() => setMainImage(image)}
                                        />
                                    ))
                                ) : (
                                    <p>No additional images</p>
                                )}
                            </div>

                            <button className={styles.scrollButton} onClick={() => scrollThumbnails("right")}>›</button>
                        </div>
                    </div>
                    <h1>{product.name}</h1>
                </div>

                {/* Product Specifications */}
                <div className={styles.specifications}>
                    <h2>Specifications</h2>
                    <ul>
                        {product.specifications && Object.keys(product.specifications).length > 0 ? (
                            Object.entries(product.specifications).map(([key, value]) => (
                                <li key={key}>
                                    <strong>{key}:</strong> {value}
                                </li>
                            ))
                        ) : (
                            <p>No specifications available</p>
                        )}
                    </ul>
                </div>
            </div>
        </div>
    );
};

export default ProductDetailsScreen;
